45	/// @brief Define a combined sample function validation concept.
46	/// These concepts provide much better error messages than old-school SFINAE
47	template <typename QuantumKernel, typename... Args>
48	concept ObserveCallValid =
49	    ValidArgumentsPassed<QuantumKernel, Args...> &&
50	    HasVoidReturnType<std::invoke_result_t<QuantumKernel, Args...>>;
51	
52	namespace detail {
53	
54	/// @brief Validate observe arguments and populate the execution context and
55	/// observe policy.
56	inline void observePreamble(ExecutionContext &ctx, observe_policy &policy,
57	                            quantum_platform &platform,
58	                            const std::string &kernelName, int shots,
59	                            const cudaq::spin_op &H, std::size_t qpu_id,
60	                            std::size_t batchIteration = 0,
61	                            std::size_t totalBatchIters = 0,
62	                            std::optional<std::size_t> numTrajectories = {}) {
63	  ctx.kernelName = kernelName;
64	  ctx.spin = cudaq::spin_op::canonicalize(H);
65	  if (shots > 0)
66	    ctx.shots = shots;
67	
68	  if (numTrajectories.has_value())
69	    ctx.numberTrajectories = *numTrajectories;
70	
71	  ctx.batchIteration = batchIteration;
72	  ctx.totalIterations = totalBatchIters;
73	
74	  policy.kernelName = kernelName;
75	  policy.spin = ctx.spin.value();
76	  policy.options.shots = shots;
77	  policy.options.num_trajectories = numTrajectories;
78	  policy.noiseModel = platform.get_noise(qpu_id);
79	
80	  // For now the noise model has to be duplicated on the policy unfortunately.
81	  // get_noise() still expects it on the execution context.
82	  // TODO: Store the noise on the platform or QPU instead.
83	  ctx.noiseModel = policy.noiseModel;
84	}
85	
86	template <typename KernelFunctor>
87	auto runObservationAsync(KernelFunctor &&wrappedKernel, const spin_op &H,
88	                         quantum_platform &platform, int shots,
89	                         const std::string &kernelName, std::size_t qpu_id = 0);
90	
91	/// @brief Take the input KernelFunctor (a lambda that captures runtime
92	/// arguments and invokes the quantum kernel) and invoke the `spin_op`
93	/// observation process.
94	template <typename KernelFunctor>
95	observe_result
96	runObservation(KernelFunctor &&k, const cudaq::spin_op &H,
97	               quantum_platform &platform, int shots,
98	               const std::string &kernelName, std::size_t qpu_id = 0,
99	               std::size_t batchIteration = 0, std::size_t totalBatchIters = 0,
100	               std::optional<std::size_t> numTrajectories = {}) {
101	
102	  if (platform.is_remote(qpu_id)) {
103	    auto result = runObservationAsync(std::forward<KernelFunctor>(k), H,
104	                                      platform, shots, kernelName, qpu_id);
105	    return result.get();
106	  }
107	
108	  ExecutionContext ctx("observe", shots, qpu_id);
109	  observe_policy policy;
110	  observePreamble(ctx, policy, platform, kernelName, shots, H, qpu_id,
111	                  batchIteration, totalBatchIters, numTrajectories);
112	
113	  return detail::launch(policy, qpu_id, ctx, platform,
114	                        std::forward<KernelFunctor>(k));
115	}
116	
117	/// @brief Take the input KernelFunctor (a lambda that captures runtime
118	/// arguments and invokes the quantum kernel) and invoke the `spin_op`
119	/// observation process asynchronously
120	template <typename KernelFunctor>
121	auto runObservationAsync(KernelFunctor &&wrappedKernel, const spin_op &H,
122	                         quantum_platform &platform, int shots,
123	                         const std::string &kernelName, std::size_t qpu_id) {
124	  if (qpu_id >= platform.num_qpus()) {
125	    throw std::invalid_argument("Provided qpu_id " + std::to_string(qpu_id) +
126	                                " is invalid (must be < " +
127	                                std::to_string(platform.num_qpus()) +
128	                                " i.e. platform.num_qpus())");
129	  }
130	
131	  // Could be that the platform we are running on is
132	  // remotely hosted, if so, we can't do asynchronous execution with a
133	  // separate thread, the separate thread is the remote server invocation
134	  if (platform.is_remote(qpu_id)) {
135	    ExecutionContext ctx("observe", shots, qpu_id);
136	    async_observe_policy async_policy;
137	    observePreamble(ctx, async_policy.inner, platform, kernelName, shots, H,
138	                    qpu_id);
139	    return detail::launch(async_policy, qpu_id, ctx, platform,
140	                          std::forward<KernelFunctor>(wrappedKernel));
141	  }
142	
143	  // If the platform is not remote, then we can handle asynchronous execution
144	  // via a new worker thread.
145	  std::size_t seed = cudaq::get_random_seed();
146	  KernelExecutionTask task(
147	      [&, H, qpu_id, shots, kernelName, seed,
148	       kernel = std::forward<KernelFunctor>(wrappedKernel)]() mutable {
149	        if (seed > 0)
150	          cudaq::set_random_seed(seed);
151	        return detail::runObservation(kernel, H, platform, shots, kernelName,
152	                                      qpu_id)
153	            .raw_data();
154	      });
155	
156	  return async_observe_result(
157	      detail::future(platform.enqueueAsyncTask(qpu_id, task)), &H);
158	}
159	
160	/// @brief Distribute the expectation value computations among the
161	/// available platform QPUs. The `asyncLauncher` functor takes as input the
162	/// QPU index and the `spin_op` chunk and returns an `async_observe_result`.
163	inline auto distributeComputations(
164	    std::function<async_observe_result(std::size_t, const spin_op &)>
165	        &&asyncLauncher,
166	    const spin_op &H, std::size_t nQpus) {
167	
168	  auto op = cudaq::spin_op::canonicalize(H);
169	  // Distribute the given spin_op into subsets for each QPU
170	  auto spins = op.distribute_terms(nQpus);
171	
172	  // Observe each sub-spin_op asynchronously
173	  std::vector<async_observe_result> asyncResults;
174	  for (std::size_t i = 0; auto &op : spins) {
175	    asyncResults.emplace_back(asyncLauncher(i, op));
176	    i++;
177	  }
178	
179	  // Wait for the results, should be executing
180	  // in parallel on the available QPUs.
181	  double result = 0.0;
182	  sample_result data;
183	  for (auto &asyncResult : asyncResults) {
184	    auto res = asyncResult.get();
185	    auto incomingData = res.raw_data();
186	    result += incomingData.expectation();
187	    data += incomingData;
188	  }
189	
190	  return observe_result(result, op, data);
191	}
192	
193	} // namespace detail
194	
195	/// \overload
196	/// \brief Compute the expected value of `H` with respect to `kernel(Args...)`.
197	template <typename QuantumKernel, typename... Args>
198	  requires ObserveCallValid<QuantumKernel, Args...>
199	observe_result observe(QuantumKernel &&kernel, const spin_op &H,
200	                       Args &&...args) {
201	  // Run this SHOTS times
202	  auto &platform = cudaq::get_platform();
203	  auto kernelName = cudaq::getKernelName(kernel);
204	  return detail::runObservation(
205	      [&kernel, &args...]() mutable { kernel(std::forward<Args>(args)...); }, H,
206	      platform, /*shots=*/-1, kernelName);
207	}
208	
209	/// @brief Compute the expected value of every `spin_op` provided in
210	/// `SpinOpContainer` (a range concept) with respect to `kernel(Args...)`.
211	/// Return a `std::vector<observe_result>`.
212	template <typename QuantumKernel, typename SpinOpContainer, typename... Args>
213	  requires ObserveCallValid<QuantumKernel, Args...> &&
214	           std::ranges::range<SpinOpContainer>
215	std::vector<observe_result> observe(QuantumKernel &&kernel,
216	                                    const SpinOpContainer &termList,
217	                                    Args &&...args) {
218	  // Here to give a more comprehensive error if the container does not contain
219	  // values of type spin_op_term.
220	  typedef typename SpinOpContainer::value_type value_type;
221	  static_assert(std::is_same_v<spin_op_term, value_type>,
222	                "term list must be a container of spin_op_term");
223	
224	  // Run this SHOTS times
225	  auto &platform = cudaq::get_platform();
226	  auto kernelName = cudaq::getKernelName(kernel);
227	
228	  // Convert all spin_ops to a single summed spin_op
229	  auto op = cudaq::spin_op::empty();
230	  for (auto &o : termList)
231	    op += cudaq::spin_op_term::canonicalize(o);
232	
233	  // Run the observation
234	  auto result = detail::runObservation(
235	      [&kernel, &args...]() mutable { kernel(std::forward<Args>(args)...); },
236	      op, platform, /*shots=*/-1, kernelName);
237	
238	  // Convert back to a vector of results
239	  std::vector<observe_result> results;
240	  for (const auto &term : op)
241	    results.emplace_back(result.expectation(term), term, result.counts(term));
242	
243	  return results;
244	}
245	
246	// Doxygen: ignore overloads with `DistributionType`s, preferring the simpler
247	// ones
248	/// @cond
249	/// @brief Compute the expected value of `H` with respect to `kernel(Args...)`.
250	/// Distribute the work `amongst` available QPUs on the platform in parallel.
251	/// This distribution can occur on multi-GPU multi-node platforms, multi-GPU
252	/// single-node platforms, or multi-node no-GPU platforms. Programmers must
253	/// indicate the distribution type via the corresponding template types
254	/// (cudaq::mgmn, cudaq::mgsn, cudaq::mn).
255	template <typename DistributionType, typename QuantumKernel, typename... Args>
256	  requires ObserveCallValid<QuantumKernel, Args...>
257	observe_result observe(std::size_t shots, QuantumKernel &&kernel,
258	                       const spin_op &H, Args &&...args) {
259	  // Run this SHOTS times
260	  auto &platform = cudaq::get_platform();
261	  // Does platform support parallelism? Need a check here
262	  if (!platform.supports_task_distribution())
263	    throw std::runtime_error(
264	        "The current quantum_platform does not support parallel distribution "
265	        "of observe() expectation value computations.");
266	
267	  auto nQpus = platform.num_qpus();
268	  if constexpr (std::is_same_v<DistributionType, parallel::thread>) {
269	    if (nQpus == 1)
270	      printf(
271	          "[cudaq::observe warning] distributed observe requested but only 1 "
272	          "QPU available. no speedup expected.\n");
273	    // Let's distribute the work among the QPUs on this node.
274	    return detail::distributeComputations(
275	        [&kernel, shots, ... args = std::forward<Args>(args)](
276	            std::size_t i, const spin_op &op) mutable {
277	          return observe_async(shots, i, std::forward<QuantumKernel>(kernel),
278	                               op, std::forward<Args>(args)...);
279	        },
280	        H, nQpus);
281	  } else if (std::is_same_v<DistributionType, parallel::mpi>) {
282	
283	    // This is an MPI distribution, where each node has N GPUs.
284	    if (!mpi::is_initialized())
285	      throw std::runtime_error("Cannot use mgmn multi-node observe() without "
286	                               "MPI (did you initialize MPI?).");
287	
288	    // Note - For MGMN, we assume that nQpus == num visible GPUs for this local
289	    // rank.
290	
291	    // FIXME, how do we handle an mpi run where each rank
292	    // is targeting the same GPU? Should we even allow that?
293	
294	    // Get the rank and the number of ranks
295	    auto rank = mpi::rank();
296	    auto nRanks = mpi::num_ranks();
297	
298	    // Each rank gets a subset of the spin terms
299	    auto spins = H.distribute_terms(nRanks);
300	
301	    // Get this rank's set of spins to compute
302	    auto localH = spins[rank].canonicalize();
303	
304	    // Distribute locally, i.e. to the local nodes QPUs
305	    auto localRankResult = detail::distributeComputations(
306	        [&kernel, shots, ... args = std::forward<Args>(args)](
307	            std::size_t i, const spin_op &op) mutable {
308	          return observe_async(shots, i, std::forward<QuantumKernel>(kernel),
309	                               op, std::forward<Args>(args)...);
310	        },
311	        localH, nQpus);
312	
313	    // combine all the data via an all_reduce
314	    auto exp_val = localRankResult.expectation();
315	    auto globalExpVal = mpi::all_reduce(exp_val, std::plus<double>());
316	    // we need the canonicalized version of H -
317	    // maybe we can get it from the context instead?
318	    cudaq::spin_op canonH;
319	    for (auto &&terms : spins)
320	      canonH += std::move(terms);
321	    return observe_result(globalExpVal, canonH);
322	
323	  } else
324	    throw std::runtime_error("Invalid cudaq::par execution type.");
325	}
326	
327	template <typename DistributionType, typename QuantumKernel, typename... Args>
328	  requires ObserveCallValid<QuantumKernel, Args...>
329	observe_result observe(QuantumKernel &&kernel, const spin_op &H,
330	                       Args &&...args) {
331	  return observe<DistributionType>(/*shots=*/-1,
332	                                   std::forward<QuantumKernel>(kernel), H,
333	                                   std::forward<Args>(args)...);
334	}
335	/// \endcond
336	
337	/// \overload
338	/// \brief Compute the expected value of `H` with respect to `kernel(Args...)`.
339	/// Specify the number of shots.
340	template <typename QuantumKernel, typename... Args>
341	  requires ObserveCallValid<QuantumKernel, Args...>
342	observe_result observe(std::size_t shots, QuantumKernel &&kernel,
343	                       const spin_op &H, Args &&...args) {
344	  // Run this SHOTS times
345	  auto &platform = cudaq::get_platform();
346	  auto kernelName = cudaq::getKernelName(kernel);
347	
348	  // Does this platform expose more than 1 QPU
349	  // If so, let's distribute the work among the QPUs
350	  if (auto nQpus = platform.num_qpus(); nQpus > 1)
351	    return detail::distributeComputations(
352	        [&kernel, shots, ... args = std::forward<Args>(args)](
353	            std::size_t i, const spin_op &op) mutable {
354	          return observe_async(shots, i, std::forward<QuantumKernel>(kernel),
355	                               op, std::forward<Args>(args)...);
356	        },
357	        H, nQpus);
358	
359	  return detail::runObservation(
360	      [&kernel, &args...]() mutable { kernel(std::forward<Args>(args)...); }, H,
361	      platform, shots, kernelName);
362	}
363	
364	/// \brief Compute the expected value of `H` with respect to `kernel(Args...)`.
365	/// Specify the observation options
366	template <typename QuantumKernel, typename... Args>
367	  requires ObserveCallValid<QuantumKernel, Args...>
368	observe_result observe(const observe_options &options, QuantumKernel &&kernel,
369	                       const spin_op &H, Args &&...args) {
370	  auto &platform = cudaq::get_platform();
371	  auto kernelName = cudaq::getKernelName(kernel);
372	  auto shots = options.shots;
373	
374	  platform.set_noise(&options.noise);
375	
376	  auto ret = detail::runObservation(
377	      [&kernel, &args...]() mutable { kernel(std::forward<Args>(args)...); }, H,
378	      platform, shots, kernelName, /*qpu_id=*/0,
379	      /*batchIteration=*/0,
380	      /*totalBatchIters=*/0, options.num_trajectories);
381	
382	  platform.reset_noise();
383	  return ret;
384	}
385	
386	/// \brief Asynchronously compute the expected value of `H` with respect to
387	/// `kernel(Args...)`.
388	template <typename QuantumKernel, typename... Args>
389	  requires ObserveCallValid<QuantumKernel, Args...>
390	auto observe_async(const std::size_t qpu_id, QuantumKernel &&kernel,
391	                   const spin_op &H, Args &&...args) {
392	  // Run this SHOTS times
393	  auto &platform = cudaq::get_platform();
394	  auto kernelName = cudaq::getKernelName(kernel);
395	
396	  return detail::runObservationAsync(
397	      [&kernel, ... args = std::forward<Args>(args)]() mutable {
398	        kernel(std::forward<Args>(args)...);
399	      },
400	      H, platform, /*shots=*/-1, kernelName, qpu_id);
401	}
402	
403	/// \brief Asynchronously compute the expected value of `H` with respect to
404	/// `kernel(Args...)`. Specify the shots.
405	template <typename QuantumKernel, typename... Args>
406	  requires ObserveCallValid<QuantumKernel, Args...>
407	auto observe_async(std::size_t shots, std::size_t qpu_id,
408	                   QuantumKernel &&kernel, const spin_op &H, Args &&...args) {
409	  // Run this SHOTS times
410	  auto &platform = cudaq::get_platform();
411	  auto kernelName = cudaq::getKernelName(kernel);
412	
413	  return detail::runObservationAsync(
414	      [&kernel, ... args = std::forward<Args>(args)]() mutable {
415	        kernel(std::forward<Args>(args)...);
416	      },
417	      H, platform, shots, kernelName, qpu_id);
418	}
419	
420	/// \brief Asynchronously compute the expected value of \p H with respect to
421	/// `kernel(Args...)`. Default to the `0-th` QPU.
422	template <typename QuantumKernel, typename... Args>
423	  requires ObserveCallValid<QuantumKernel, Args...>
424	auto observe_async(QuantumKernel &&kernel, const spin_op &H, Args &&...args) {
425	  return observe_async(0, std::forward<QuantumKernel>(kernel), H,
426	                       std::forward<Args>(args)...);
427	}
428	
429	/// @overload
430	/// @brief Run the standard observe functionality over a set of `N`
431	/// argument packs. For a kernel with signature `void(Args...)`, this
432	/// function takes as input a set of `vector<Arg>...`, a vector for
433	/// each argument type in the kernel signature. The vectors must be of
434	/// equal length, and the `i-th` element of each vector is used `i-th`
435	/// execution of the standard observe function. Results are collected
436	/// from the execution of every argument set and returned.
437	template <typename QuantumKernel, typename... Args>
438	  requires ObserveCallValid<QuantumKernel, Args...>
439	std::vector<observe_result> observe(QuantumKernel &&kernel, const spin_op &H,
440	                                    ArgumentSet<Args...> &&params) {
441	  // Get the platform and query the number of quantum computers
442	  auto &platform = cudaq::get_platform();
