444	
445	  // Create the functor that will broadcast the observations across
446	  // all requested argument sets provided.
447	  detail::BroadcastFunctorType<observe_result, Args...> functor =
448	      [&](std::size_t qpuId, std::size_t counter, std::size_t N,
449	          Args &...singleIterParameters) -> observe_result {
450	    auto kernelName = cudaq::getKernelName(kernel);
451	    return detail::runObservation(
452	        [&kernel, &singleIterParameters...]() mutable {
